{
    "friendly_name": "boarding_notification",
    "language": "en",
    "variables": {
        "1":"name",
        "2":"11"
    },
    "types": {
        "twilio/text": {
            "body": "Hi {{1}}, \n Your flight will depart from gate {{2}}."
        }
    }
}

{
    "friendly_name": "variable_media",
    "language": "en",
    "variables": {"1":"library-logo-resource2x.width-1000.png"},
    "types": {
        "twilio/media": {
        "body": "A new image was shared with your account",
        "media": ["https://www.example.com/images/{{1}}"]
        }
    }
}

{
    "friendly_name": "delivery_confirmation",
    "language": "en",
    "types": {
        "twilio/text": {
            "body": "Your items are ready for pickup at 101 Spear, San Francisco, CA 94105."
        },
        "twilio/location": {
            "latitude": 37.793160017538895, 
            "longitude": -122.39292865432677,
            "label": "Your items are ready for pickup."
        }
    }
}

{
    "friendly_name": "owl_sale_list",
    "language": "en",
    "variables": {
        "1": "end_date"
    },
    "types": {
        "twilio/list-picker": {
            "body": "Owl Air Flash Sale! Hurry! Sale ends on {{1}}!",
            "button": "Select a destination",
            "items": [
                {
                    "item": "SFO to NYC for $299",
                    "description": "Owl Air Flight 1337 to LGA",
                    "id": "SFO1337_postbackpayload1"
                },
                {
                    "item": "OAK to Denver for $149",
                    "description": "Owl Air Flight 5280 to DEN",
                    "id": "OAK5280_postbackpayload2"
                },
                {
                    "item": "LAX to Chicago for $199",
                    "description": "Owl Air Flight 96 to ORD",
                    "id": "LAX96_postbackpayload3"
                }
            ]
        }
    }
}

{
    "friendly_name": "quickreply_help",
    "language": "en",
    "variables": {
        "1":"Name"
    },
    "types": {
        "twilio/text": {
            "body": "Hi {{1}}, \n Thanks for contacting Owl Air Support. How can I help?."
        },
        "twilio/quick-reply": {
            "body": "Hi {{1}}, \n Thanks for contacting Owl Air Support. How can I help?",
            "actions": [
                {
                    "id": "postbackpayload1",
                    "title": "Check flight status"
                },
                {
                    "id": "postbackpayload2",
                    "title": "Check gate number"
                },
                {
                    "id": "postbackpayload3",
                    "title": "Speak with an agent"
                }
            ]
        }
    }
}

{
    "friendly_name": "quickreply_help",
    "language": "en",
    "variables": {"1": "flight_number", 
                "2": "arrival_city",
                "3": "departure_time",
                "4": "gate_number",
                "5": "url_suffix"},
    "types": {
    "twilio/call-to-action": {
      "body": "Owl Air: We will see you soon! Flight {{1}} to {{2}} departs at {{3}} from Gate {{4}}.",
      "actions": [{
          "type": "URL",
          "title": "Check Flight Status",
          "url": "https://owlair.com/{{5}}"
        },
        {
          "type": "PHONE_NUMBER",
          "title": "Call Support",
          "phone": "+18005551234"
      }]
    }
  }
}

{
    "friendly_name": "card_elite_status",
    "language": "en",
    "variables": {
        "1": "coupon_code"
    },
    "types": {
        "twilio/card": {
                    "title": "Congratulations, you've reached Elite status! Add code {{1}} for 10% off.",
                    "subtitle": "To unsubscribe, reply Stop",
                    "actions": [
                        {
                            "url": "https://twilio.com/",
                            "title": "Order Online",
                            "type": "URL"
                        },
                        {
                            "phone": "+15551234567",
                            "title": "Call Us",
                            "type": "PHONE_NUMBER"
                        }
                    ]
                }
    }
}

{
    "friendly_name": "owl_coupon_card",
    "language": "en",
    "variables": {
        "1": "coupon_code"
    },
    "types": {
        "whatsapp/card": {
                    "body": "Congratulations, you have reached Elite status! Add code {{1}} for 10% off.",
                    "header_text": "This is a {{1}} card",
                    "footer": "To unsubscribe, reply Stop",
                    "actions": [
                        {
                            "url": "https://twilio.com/",
                            "title": "Order Online",
                            "type": "URL"
                        },
                        {
                            "phone": "+15551234567",
                            "title": "Call Us",
                            "type": "PHONE_NUMBER"
                        }
                    ]
                }
    }
}
